#include <iostream>
using namespace std;

class Animal {
public:
    void eat() {
        cout << "Eating..." << endl;
    }
};

class Dog : public Animal {
public:
    void bark() {
        cout << "Barking..." << endl;
    }
};

int main() {
    Dog d;
    d.eat();
    d.bark();
    return 0;
}

#include <iostream>
using namespace std;

class Base {
protected:
    int id;
};

class Derived : public Base {
public:
    void setId(int i) {
        id = i; // Allowed
    }
    void display() {
        cout << "ID: " << id << endl;
    }
};

int main() {
    Derived d;
    d.setId(55);
    d.display();
    return 0;
}

#include <iostream>
using namespace std;

class GrandParent { public: void gp() { cout << "GP\n"; } };
class Parent : public GrandParent { public: void p() { cout << "P\n"; } };
class Child : public Parent { public: void c() { cout << "C\n"; } };

int main() {
    Child obj;
    obj.gp();
    obj.p();
    obj.c();
    return 0;
}

