#include <iostream>
using namespace std;

class Base {
public:
    Base(int x) { cout << "Base: " << x << endl; }
};

class Derived : public Base {
public:
    Derived(int y) : Base(y) {
        cout << "Derived" << endl;
    }
};

int main() {
    Derived d(10);
    return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
    void display() { cout << "Base Display\n"; }
};

class Derived : public Base {
public:
    // Override
    void display() { cout << "Derived Display\n"; }
};

int main() {
    Derived d;
    d.display();
    return 0;
}

void someFunc() {
    Base::display(); // Use scope resolution
}

